/// Stable FNV-1a hash so a given [id] always maps to the same variant across
/// clients and launches (independent of Dart's per-run String.hashCode seed).
int _stableHash(String id) {
  var h = 0x811c9dc5;
  for (var i = 0; i < id.length; i++) {
    h ^= id.codeUnitAt(i) & 0xff;
    h = (h * 0x01000193) & 0xffffffff;
  }
  return h;
}

/// Deterministic default avatar for a player without a customized look.
String defaultAvatarSvgForId(String? id) {
  if (defaultAvatarVariants.isEmpty) return '';
  final key = (id == null || id.isEmpty) ? 'hooprank' : id;
  return defaultAvatarVariants[_stableHash(key) % defaultAvatarVariants.length];
}
